import{_ as t,o as r,c as l,ai as n}from"./chunks/framework.DMjte4z8.js";const h=JSON.parse('{"title":"编辑器界面功能全览","description":"","frontmatter":{"title":"编辑器界面功能全览","category":"getting-started","updated":"2026-04-28T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"manual","sources":["https://bentleysystems.service-now.com/community","https://www.google.com/","https://zhuanlan.zhihu.com/p/627356428"]},"headers":[],"relativePath":"getting-started/编辑器界面功能全览.md","filePath":"getting-started/编辑器界面功能全览.md","lastUpdated":1777383225000}'),s={name:"getting-started/编辑器界面功能全览.md"};function a(i,o,e,g,u,q){return r(),l("div",null,[...o[0]||(o[0]=[n('<h1 id="编辑器界面功能全览" tabindex="-1">编辑器界面功能全览 <a class="header-anchor" href="#编辑器界面功能全览" aria-label="Permalink to “编辑器界面功能全览”">​</a></h1><h2 id="编辑器界面概述与基础导航" tabindex="-1">编辑器界面概述与基础导航 <a class="header-anchor" href="#编辑器界面概述与基础导航" aria-label="Permalink to “编辑器界面概述与基础导航”">​</a></h2><p>本节将带你认识 Warcraft III 地图编辑器的整体界面布局。完成学习后，你将能够熟练找到各种功能面板，知道常用的快捷键操作，为后续的地图制作打下基础。</p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>第一步：打开编辑器</strong> — 双击桌面或开始菜单中的 &quot;World Editor&quot; 图标启动编辑器[^2]。首次启动可能需要等待几秒加载资源，耐心等待即可。</p></li><li><p><strong>第二步：认识主界面分区</strong> — 打开后，你会看到编辑器顶部有<strong>菜单栏</strong>（文件、编辑、视图等），左侧是<strong>地形面板</strong>（用于摆放地形装饰物），右侧是<strong>物编面板</strong>（管理游戏单位），底部是<strong>触发器面板</strong>（编写游戏逻辑）[^1]。</p></li><li><p><strong>第三步：了解菜单栏</strong> — 菜单栏从左到右分别是：文件（新建、打开、保存地图）、编辑（撤销、重做、复制粘贴）、视图（切换面板显示）、模块（切换不同编辑模式）、游戏（测试地图）、窗口（排列面板布局）、帮助（官方教程）[^3]。</p></li><li><p><strong>第四步：使用工具栏</strong> — 菜单栏下方是快捷工具栏，鼠标悬停在图标上会显示功能提示。常用的包括：![image]选择工具、刷子地形、区域绘制、单位放置等[^1]。</p></li><li><p><strong>第五步：切换编辑模式</strong> — 编辑器左下角有标签页，可在&quot;地形编辑器&quot;、&quot;触发器编辑器&quot;、&quot;声音编辑器&quot;等模式间切换。制作地图时最常用的是前两个模式[^3]。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：如果某个面板不见了，按快捷键 <code>F6</code> 可以重置所有面板布局到默认状态。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常误关面板后找不到，建议先把界面布局保存下来（菜单栏 → 窗口 → 保存布局），这样每次打开都会恢复你习惯的界面。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能独立打开编辑器并识别各个主要区域。建议花1-2分钟随意点击各个菜单和面板，感受一下界面布局。下一节我们将学习如何创建一张空白地图并设置基本参数。</p><h2 id="地形编辑器功能详解" tabindex="-1">地形编辑器功能详解 <a class="header-anchor" href="#地形编辑器功能详解" aria-label="Permalink to “地形编辑器功能详解”">​</a></h2><p>本节将带你认识<strong>地图编辑器</strong>中最常用的<strong>地形编辑器</strong>界面。你将学会如何塑造地图的高低起伏、铺设地表纹理、放置装饰物，以及设置水域和悬崖等障碍区域。学完本节后，你就能亲手创建一张具有基本外观的游戏地图了！</p><hr><h3 id="地形塑造与高度调整" tabindex="-1">地形塑造与高度调整 <a class="header-anchor" href="#地形塑造与高度调整" aria-label="Permalink to “地形塑造与高度调整”">​</a></h3><p>在左侧工具栏中，找到并点击<strong>&quot;地形塑造&quot;</strong>工具（图标像一座小山丘）。[^1]</p><ol><li><strong>打开高度工具</strong> — 在工具栏下方会出现几个子选项，点击<strong>&quot;升高/降低地形&quot;</strong>按钮[^2]</li><li><strong>设置笔刷大小</strong> — 滑动<strong>&quot;笔刷尺寸&quot;</strong>滑块，选择影响的区域大小（新手建议从中等大小开始练习）</li><li><strong>绘制地形</strong> — 在地图上按住鼠标左键<strong>向上拖动</strong>是升高地形，向下拖动是降低地形[^3]</li><li><strong>调整高度级别</strong> — 在右侧属性面板中，你可以看到<strong>&quot;高度等级&quot;</strong>数值（1-16级），级别越高地形越高</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手常常用力过大，一次操作就挖出太深的坑。解决方法：按住<strong>Shift键</strong>可以<strong>临时切换到降低模式</strong>，松开恢复升高，这样更容易控制力度。</p></blockquote><blockquote><p><strong>💡 新手提示</strong>：使用<strong>&quot;平滑&quot;工具</strong>可以让陡峭的山坡变得自然过渡，使地形看起来更真实。</p></blockquote><hr><h3 id="地形纹理与地表装饰" tabindex="-1">地形纹理与地表装饰 <a class="header-anchor" href="#地形纹理与地表装饰" aria-label="Permalink to “地形纹理与地表装饰”">​</a></h3><p>完成基本地形后，接下来要为地图&quot;穿衣服&quot;——铺上好看的纹理和装饰物。</p><ol><li><strong>打开纹理面板</strong> — 在工具栏点击<strong>&quot;地形刷&quot;</strong>图标（像一把刷子）[^4]</li><li><strong>选择地表类型</strong> — 在弹出的纹理列表中，左键点击选择你想要的地表（如草地、土地、雪地等）</li><li><strong>涂抹地表</strong> — 在地图上按住并拖动鼠标，即可将选中的纹理<strong>&quot;画&quot;</strong>到地面上</li><li><strong>添加地表装饰物</strong> — 切换到<strong>&quot;装饰物&quot;</strong>标签页（图标是小树），这里有石头、树木、花草等模型[^5]</li><li><strong>放置装饰物</strong> — 选择喜欢的装饰物后，在地图上<strong>左键单击</strong>即可放置</li></ol><blockquote><p><strong>💡 新手提示</strong>：不要把装饰物放得太密集！想象真实世界中，树木和石头会自然散布。如果需要大面积复制，可以按住<strong>Ctrl+左键</strong>快速放置多个。</p></blockquote><hr><h3 id="悬崖、水域与可通行区域" tabindex="-1">悬崖、水域与可通行区域 <a class="header-anchor" href="#悬崖、水域与可通行区域" aria-label="Permalink to “悬崖、水域与可通行区域”">​</a></h3><p>悬崖和水域不仅影响地图外观，还决定了<strong>单位能否通过</strong>——这是游戏逻辑的基础！</p><ol><li><strong>绘制悬崖</strong> — 在工具栏选择<strong>&quot;悬崖&quot;</strong>工具（图标是层叠的山崖）[^6]</li><li><strong>选择悬崖高度</strong> — 在属性面板中设定悬崖的<strong>相对高度差</strong></li><li><strong>涂抹悬崖</strong> — 在高低地形的交界处涂抹，创建垂直的崖壁</li><li><strong>添加水域</strong> — 切换到<strong>&quot;水域&quot;</strong>工具（蓝色波浪图标），从列表中选择水类型（河流、湖泊、海洋等）[^7]</li><li><strong>绘制水区</strong> — 在地图低洼处涂抹，即可生成水域区域</li><li><strong>检查可行走区域</strong> — 按下<strong>Ctrl+D</strong>打开<strong>&quot;路径网格&quot;</strong>视图，绿色表示可通过，红色表示阻挡</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手常常忘记检查路径网格，导致单位被水或悬崖挡住无法到达目的地。<strong>务必在完成地图后，按Ctrl+D检查一遍所有可行走区域！</strong></p></blockquote><blockquote><p><strong>💡 新手提示</strong>：水域的深度可以通过调整工具属性中的<strong>&quot;深度等级&quot;</strong>来控制，水越深对某些单位的影响越大。</p></blockquote><hr><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成以上三个部分后，你的地图已经具备基本的<strong>外观结构</strong>和<strong>可通行逻辑</strong>。你可以：</p><ul><li>✅ 创建起伏的山脉和平原</li><li>✅ 为不同区域铺设适合的地表纹理</li><li>✅ 放置树木、石头等装饰物让场景更丰富</li><li>✅ 设置悬崖和水域作为天然屏障</li><li>✅ 确认单位能否正常通过各个区域</li></ul><p>下一步，你可以继续学习<strong>单位放置</strong>或<strong>触发器基础</strong>，为你的地图添加游戏玩法！</p><h2 id="物体编辑器基础" tabindex="-1">物体编辑器基础 <a class="header-anchor" href="#物体编辑器基础" aria-label="Permalink to “物体编辑器基础”">​</a></h2><p>本节我们将学习如何使用&quot;物体编辑器&quot;（Object Editor）——这是管理地图中所有单位、物品、技能和科技树的核心工具[^1]。学完本节后，你将能够创建属于自己的英雄和士兵，设计回血药水等物品，并为它们添加各种战斗技能。</p><h3 id="单位创建与基本属性" tabindex="-1">单位创建与基本属性 <a class="header-anchor" href="#单位创建与基本属性" aria-label="Permalink to “单位创建与基本属性”">​</a></h3><ol><li><p><strong>打开物体编辑器</strong> — 在WE主界面顶部菜单栏点击&quot;高级&quot;→&quot;物体编辑器&quot;，或直接按快捷键F6[^2]</p></li><li><p><strong>创建一个新单位</strong> — 在左侧面板选择&quot;单位&quot;选项卡，点击&quot;新建单位&quot;按钮（绿色加号图标）。新单位会自动生成一个临时名称如&quot;新单位0000&quot;</p></li><li><p><strong>修改单位基本属性</strong> — 在右侧属性面板中，你可以修改以下常用设置：</p><ul><li><strong>名称</strong>：单位在游戏中的显示名字</li><li><strong>生命值</strong>：单位能承受多少伤害</li><li><strong>攻击力</strong>：单位每次攻击造成多少伤害</li><li><strong>护甲类型</strong>：影响受到的伤害类型（轻甲、重甲等）</li><li><strong>移动速度</strong>：数值越大跑得越快</li></ul></li></ol><blockquote><p><strong>💡 新手提示</strong>：单位名称只是显示用，不会影响游戏内部识别。真正重要的是&quot;编辑器前缀&quot;字段，它决定了单位在触发器中的代号。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手把&quot;生命值&quot;和&quot;生命恢复&quot;搞混——生命值是总量，生命恢复是每秒自动回复的血量。如果你希望单位能自动回血，记得两个都要设置。</p></blockquote><h3 id="物品、技能与升级科技" tabindex="-1">物品、技能与升级科技 <a class="header-anchor" href="#物品、技能与升级科技" aria-label="Permalink to “物品、技能与升级科技”">​</a></h3><ol><li><p><strong>物品创建</strong> — 在物体编辑器左侧选择&quot;物品&quot;选项卡，同样点击&quot;新建物品&quot;按钮</p></li><li><p><strong>物品属性设置</strong> — 物品和单位类似但多了&quot;可使用&quot;和&quot;冷却时间&quot;等属性。勾选&quot;可使用&quot;后，你需要额外设置：</p><ul><li><strong>使用效果</strong>：选择触发器或直接设置回复/增益数值</li><li><strong>使用范围</strong>：影响范围（对周围队友生效的群补道具需要设置此参数）</li></ul></li><li><p><strong>技能与科技树</strong> — 分别在&quot;技能&quot;和&quot;科技&quot;选项卡中创建。需要注意的是，技能必须先&quot;赋值&quot;给某个单位才能生效——在单位的&quot;科技允许&quot;或&quot;可研究技能&quot;属性中添加对应技能ID[^3]</p></li></ol><h3 id="自定义单位导入方法" tabindex="-1">自定义单位导入方法 <a class="header-anchor" href="#自定义单位导入方法" aria-label="Permalink to “自定义单位导入方法”">​</a></h3><ol><li><p><strong>准备模型文件</strong> — 自定义单位需要.mdx或.mdl格式的模型文件，以及配套的.blp贴图文件。将它们放入地图根目录的&quot;war3map.w3q&quot;或&quot;Units&quot;文件夹中</p></li><li><p><strong>导入到地图</strong> — 在WE菜单选择&quot;文件&quot;→&quot;导入管理器&quot;（Ctrl+I），将模型和贴图文件添加进去，文件名会自动注册到游戏资源库</p></li><li><p><strong>应用自定义模型</strong> — 回到物体编辑器，选中你要修改的单位，找到&quot;美术 - 模型文件&quot;字段，点击浏览按钮选择你导入的模型文件</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：模型显示&quot;红叉&quot;通常是贴图路径错误或文件未正确导入。请检查导入管理器中贴图文件的路径是否与模型内嵌路径一致。</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够：</p><ul><li>✅ 创建新单位并设置基本的攻防属性</li><li>✅ 制作可使用的物品（如回蓝药水）</li><li>✅ 为单位添加技能并设置科技树</li><li>✅ 将自定义3D模型应用到你的单位上</li></ul><p>这些是制作RPG地图最基础的&quot;建筑砖块&quot;，建议先熟练掌握单位属性设置，再逐步尝试物品和技能的高级功能。</p><h2 id="触发编辑器入门" tabindex="-1">触发编辑器入门 <a class="header-anchor" href="#触发编辑器入门" aria-label="Permalink to “触发编辑器入门”">​</a></h2><p>本节介绍Warcraft III中触发编辑器的基础用法。你将理解什么是&quot;触发器&quot;，以及如何用搭积木的方式实现游戏中的交互逻辑。完成学习后，你能够创建简单的触发器来响应游戏事件。</p><h3 id="触发器核心概念解析" tabindex="-1">触发器核心概念解析 <a class="header-anchor" href="#触发器核心概念解析" aria-label="Permalink to “触发器核心概念解析”">​</a></h3><p>触发器由三个基本部分组成：事件（Event）、条件（Condition）和动作（Action）。[^3]</p><p><strong>事件</strong>是指触发器启动的&quot;开关&quot;，比如某个单位死亡、玩家按下键盘、倒计时结束等。 <strong>条件</strong>是一个&quot;过滤器&quot;，只有当条件满足时，触发器才会继续执行后面的动作。 <strong>动作</strong>就是具体要执行的&quot;操作&quot;，比如显示一段文字、创建单位、修改分数等。</p><blockquote><p><strong>💡 新手提示</strong>：可以把触发器想象成现实中的&quot;自动门&quot;——事件是&quot;有人走近&quot;，条件是&quot;确认是活人&quot;，动作是&quot;开门&quot;。三部分缺一不可。</p></blockquote><h3 id="常用事件与动作类型" tabindex="-1">常用事件与动作类型 <a class="header-anchor" href="#常用事件与动作类型" aria-label="Permalink to “常用事件与动作类型”">​</a></h3><p><strong>常用事件类型：</strong></p><ul><li><strong>单位事件</strong>：单位死亡、单位受伤、单位进入/离开某区域</li><li><strong>玩家事件</strong>：玩家按下某个键、玩家选择单位、玩家聊天信息</li><li><strong>游戏事件</strong>：地图初始化、计时器到期、单位被攻击</li></ul><p><strong>常用动作类型：</strong></p><ul><li><strong>单位动作</strong>：创建单位、删除单位、移动单位</li><li><strong>对话框动作</strong>：显示消息、显示对话框</li><li><strong>变量动作</strong>：设置变量值、算数运算</li></ul><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常把&quot;事件&quot;和&quot;动作&quot;搞混。记住：事件是&quot;什么发生了&quot;，动作是&quot;要做什么&quot;。</p></blockquote><h3 id="简单触发器实例演示" tabindex="-1">简单触发器实例演示 <a class="header-anchor" href="#简单触发器实例演示" aria-label="Permalink to “简单触发器实例演示”">​</a></h3><ol><li><strong>打开触发编辑器</strong> — 在WE顶部菜单栏中点击&quot;触发编辑器&quot;按钮[^1]</li><li><strong>创建新触发器</strong> — 右键点击左侧面板空白处，选择&quot;新建触发器&quot;[^2]</li><li><strong>命名触发器</strong> — 输入一个有意义的名字，比如&quot;显示欢迎消息&quot;</li><li><strong>添加事件</strong> — 双击&quot;事件&quot;目录，选择&quot;地图初始化&quot;事件</li><li><strong>添加动作</strong> — 双击&quot;动作&quot;目录，选择&quot;游戏-显示文本消息到所有玩家&quot;，输入&quot;欢迎来到我的地图！&quot;</li><li><strong>保存并测试</strong> — 按F6打开测试地图，你应该能看到屏幕上显示的欢迎消息</li></ol><blockquote><p><strong>💡 新手提示</strong>：每次修改触发器后，记得保存地图（Ctrl+S），然后再测试。养成好习惯能避免丢失辛苦编辑的内容！</p></blockquote><hr><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该已经理解了触发器的基本结构——由事件、条件、动作三部分组成。你也亲手创建了第一个触发器，能够在游戏开始时自动显示欢迎消息。这个基础非常重要，后续学习变量、循环、等待等进阶功能时，都是基于这个框架进行扩展。</p><h2 id="音效与媒体资源管理" tabindex="-1">音效与媒体资源管理 <a class="header-anchor" href="#音效与媒体资源管理" aria-label="Permalink to “音效与媒体资源管理”">​</a></h2><p>本节将教你如何在Warcraft III地图编辑器中导入和管理背景音乐、音效以及过场动画资源。学完本节后，你的RPG地图将不再只有画面，还能有动听的背景音乐烘托气氛，以及各种生动的音效让战斗和互动更加真实！</p><h3 id="背景音乐与音效导入" tabindex="-1">背景音乐与音效导入 <a class="header-anchor" href="#背景音乐与音效导入" aria-label="Permalink to “背景音乐与音效导入”">​</a></h3><ol><li><p><strong>打开资源管理器</strong> — 在编辑器顶部菜单栏中，点击“场景”菜单，然后选择“触发器编辑器”（快捷键F4）[^1]</p></li><li><p><strong>新建音效资源</strong> — 在触发器编辑器左侧的目录树中，找到“音效”文件夹并右键点击，选择“新建”→“音效”[^2]</p></li><li><p><strong>选择音频文件</strong> — 在弹出的对话框中，点击“浏览”按钮，从你的电脑中选择支持的音乐文件（注意：Warcraft III支持的音频格式为.wav和.mp3）[^3]</p></li><li><p><strong>配置播放参数</strong> — 设置音效的音量、循环模式（背景音乐需要勾选“循环”选项），以及3D音效范围（适用于环境音效）</p></li><li><p><strong>为音效命名</strong> — 在“变量”字段中为你的音效起一个容易识别的名字，比如&quot;BGM_战斗&quot;或&quot;SFX_攻击&quot;</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：建议在导入前先将所有音频文件整理到一个专门的文件夹中，并按类型命名（如&quot;music/&quot;和&quot;sfx/&quot;子文件夹），这样后续管理会方便很多。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忽略音频文件的大小限制，单个文件不要超过2MB，否则可能导致游戏加载变慢或卡顿。解决方法是将长音乐文件压缩成较低比特率（建议128kbps）。</p></blockquote><h3 id="过场动画与对话框配置" tabindex="-1">过场动画与对话框配置 <a class="header-anchor" href="#过场动画与对话框配置" aria-label="Permalink to “过场动画与对话框配置”">​</a></h3><ol><li><p><strong>准备视频文件</strong> — Warcraft III的过场动画需要转换为.w3x支持的格式，建议使用暴雪自带的视频转换工具或第三方工具将.avi/.mp4转换为.wmv格式</p></li><li><p><strong>导入过场动画</strong> — 在“触发器编辑器”中，右键“过场动画”文件夹，选择“导入过场动画”，然后选择你准备好的视频文件</p></li><li><p><strong>创建对话框</strong> — 通过“新建”→“对话框”选项创建一个新的对话框对象，设置对话框的尺寸、位置和背景样式</p></li><li><p><strong>添加对话框按钮</strong> — 在对话框中添加“对话框-添加按钮”，为每个按钮设置显示文字和触发条件</p></li><li><p><strong>设置对话框显示触发</strong> — 创建一个新的触发器，条件设为需要触发时，执行“对话框-显示”动作</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：过场动画会占用大量游戏文件体积，一个1分钟的视频可能导致地图文件增加20MB以上。如果地图需要发布到平台，建议优先使用简短的开场动画，或考虑用静态图片加文字的方式替代。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手在配置完对话框后忘记添加“对话框-隐藏”触发，导致对话框在不需要时仍然显示在其他场景中。建议在切换场景的触发器中添加隐藏对话框的动作。</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你的地图将具备完整的音频和媒体系统。背景音乐会在相应场景自动循环播放，战斗音效会随着动作触发，过场动画和对话框也能正常工作。建议先导入一组简单的音乐和音效进行测试，确保播放正常后再逐步完善。</p><h2 id="地图发布与游戏设置" tabindex="-1">地图发布与游戏设置 <a class="header-anchor" href="#地图发布与游戏设置" aria-label="Permalink to “地图发布与游戏设置”">​</a></h2><p>本节将带你完成地图发布前的最后准备工作，包括游戏规则配置、本地测试调试以及最终导出发布流程。完成本节学习后，你将能够独立发布一张可供其他玩家游玩的完整地图[^1]。</p><h3 id="地图属性与游戏规则设置" tabindex="-1">地图属性与游戏规则设置 <a class="header-anchor" href="#地图属性与游戏规则设置" aria-label="Permalink to “地图属性与游戏规则设置”">​</a></h3><p>在发布地图之前，我们需要先配置地图的基本信息和游戏规则[^2]。这一步非常重要，它决定了玩家进入游戏时看到的内容。</p><p><strong>操作步骤：</strong></p><ol><li><strong>打开地图属性面板</strong> — 点击顶部菜单栏的&quot;场景&quot;，在下拉列表中选择&quot;地图属性&quot;[^3]</li><li><strong>填写基本信息</strong> — 在弹出的&quot;地图属性&quot;对话框中，填写地图名称（这将是玩家在游戏大厅看到的名称）、作者名称等信息</li><li><strong>设置游戏规则</strong> — 找到&quot;游戏玩法&quot;相关选项，可以设置： <ul><li>允许的玩家数量（通常设置为1-12）</li><li>是否启用迷雾（战争迷雾让玩家只能看到已探索的区域）</li><li>资源限制类型</li><li>胜利/失败条件</li></ul></li><li><strong>保存设置</strong> — 点击&quot;确定&quot;按钮应用所有设置</li></ol><blockquote><p><strong>💡 新手提示</strong>：建议把地图属性设置放在开始制作时就填好，后期容易忘记。养成好习惯！</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手忘记设置&quot;允许玩家数量&quot;，导致地图最多只能2人进入。解决方法：回到地图属性中，把玩家数量改为更大的数字（如8或12）[^1]。</p></blockquote><h3 id="存档测试与问题调试" tabindex="-1">存档测试与问题调试 <a class="header-anchor" href="#存档测试与问题调试" aria-label="Permalink to “存档测试与问题调试”">​</a></h3><p>地图制作完成后，发布前必须进行充分测试。测试可以发现触发器错误、平衡性问题等[^2]。</p><p><strong>操作步骤：</strong></p><ol><li><strong>保存地图</strong> — 在测试前，按Ctrl+S保存当前地图，确保所有改动已保存</li><li><strong>启动测试</strong> — 点击编辑器顶部工具栏的绿色三角形&quot;测试地图&quot;按钮[^3]，编辑器会自动启动魔兽争霸III并加载你的地图</li><li><strong>进行游戏测试</strong> — 在测试过程中： <ul><li>尝试所有主要功能（如单位创建、技能使用、商店购买等）</li><li>观察控制台是否有红色错误信息</li><li>测试各种边界情况</li></ul></li><li><strong>退出测试</strong> — 按Alt+F4或ESC退出测试，返回编辑器</li><li><strong>查看错误日志</strong> — 如果测试中出现错误，编辑器会生成错误日志。双击错误信息可以直接跳转到问题所在的触发器[^1]</li><li><strong>修复并重复</strong> — 修复发现的问题后，再次测试直到没有明显错误</li></ol><blockquote><p><strong>💡 新手提示</strong>：测试时别只测试正常流程，也要故意做些&quot;错误操作&quot;，比如在商店不存在时尝试购买物品，这能发现潜在问题。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手测试时经常不仔细，看到游戏能运行就以为没问题。实际上很多错误只会在特定条件下触发，比如&quot;当金币为负数时崩溃&quot;这样的问题。解决方法是：尽可能多地测试各种场景[^2]。</p></blockquote><h3 id="地图导出与发布流程" tabindex="-1">地图导出与发布流程 <a class="header-anchor" href="#地图导出与发布流程" aria-label="Permalink to “地图导出与发布流程”">​</a></h3><p>测试通过后，最后一步就是导出地图并发布[^3]。</p><p><strong>操作步骤：</strong></p><ol><li><strong>最终保存</strong> — 确保地图已经完全保存，没有未保存的更改</li><li><strong>检查文件大小</strong> — 查看地图文件大小，太大的地图可能需要优化（比如减少贴图数量）</li><li><strong>导出地图</strong> — 点击菜单&quot;文件&quot;→&quot;导出地图为...&quot;，在弹出的对话框中选择保存位置和文件名</li><li><strong>选择格式</strong> — 通常选择&quot;.w3x&quot;格式（这是魔兽争霸III地图的标准格式）</li><li><strong>完成导出</strong> — 点击保存，地图文件就生成好了</li><li><strong>测试导出文件</strong> — 找到导出的.w3x文件，复制到魔兽争霸III的Maps文件夹中，启动游戏确认能正常加载</li><li><strong>发布分享</strong> — 你可以通过以下方式分享地图： <ul><li>上传到地图分享</li></ul></li></ol><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://bentleysystems.service-now.com/community" target="_blank" rel="noreferrer">Bentley Community - Communities</a> — accessed 2026-04-28 [^2]: <a href="https://www.google.com/" target="_blank" rel="noreferrer">Google</a> — accessed 2026-04-28 [^3]: <a href="https://zhuanlan.zhihu.com/p/627356428" target="_blank" rel="noreferrer">zhuanlan.zhihu.com/p/627356428</a> — accessed 2026-04-28</p>',98)])])}const c=t(s,[["render",a]]);export{h as __pageData,c as default};
